sql:
SELECT judge_name
FROM judges
WHERE years_of_experience > 5;

SELECT dancer_name
FROM dancers
WHERE school_id = 0;

SELECT dancer_name, gender
FROM dancers
ORDER BY age_group DESC;

SELECT dancers.dancer_name, schools.school_name
FROM dancers
INNER JOIN schools ON dancers.school_id = schools.school_id;

SELECT age_group, SQRT(COUNT(dancer_id)) AS sqrt_count
FROM dancers
GROUP BY age_group;

SELECT DISTINCT d.dancer_name
FROM dancers d
INNER JOIN competition_entries ce ON d.dancer_id = ce.dancer_id;

SELECT COUNT(DISTINCT user_id) AS unique_user_count
FROM access_logs
WHERE access_date BETWEEN '2023-05-01' AND '2023-05-31';

SELECT dancer_name, profile_picture_url
FROM dancers
WHERE dancer_id = 1;
